import{_ as s,o as l,c as n,a3 as t}from"./chunks/framework.BTFg6ESq.js";const c=JSON.parse('{"title":"设置概览","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/settings/index.md","filePath":"user-guide/settings/index.md","lastUpdated":1778241999000}'),o={name:"user-guide/settings/index.md"};function r(i,a,e,p,g,h){return l(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="设置概览" tabindex="-1">设置概览 <a class="header-anchor" href="#设置概览" aria-label="Permalink to &quot;设置概览&quot;">​</a></h1><blockquote><p><strong>设置系统</strong>是 AIO Hub 的配置中枢，所有个性化定制和行为控制都集中在这里。本篇将带你了解设置界面的整体布局和各选项卡的作用。</p></blockquote><hr><h2 id="界面布局" tabindex="-1">界面布局 <a class="header-anchor" href="#界面布局" aria-label="Permalink to &quot;界面布局&quot;">​</a></h2><p>点击应用顶部标题栏右侧的<strong>设置图标</strong> ⚙️，即可进入设置页面。</p><p>设置界面在桌面端采用<strong>左侧导航 + 右侧内容</strong>的经典布局示例：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────┐</span></span>
<span class="line"><span>│  ┌────────┐  ┌────────────────────────┐ │</span></span>
<span class="line"><span>│  │ 通用   │  │                        │ │</span></span>
<span class="line"><span>│  │ 外观   │  │      设置内容面板      │ │</span></span>
<span class="line"><span>│  │ AI服务 │  │                        │ │</span></span>
<span class="line"><span>│  │ 日志   │  │                        │ │</span></span>
<span class="line"><span>│  │ 工具   │  │                        │ │</span></span>
<span class="line"><span>│  │ 关于   │  │                        │ │</span></span>
<span class="line"><span>│  └────────┘  └────────────────────────┘ │</span></span>
<span class="line"><span>└─────────────────────────────────────────┘</span></span></code></pre></div><p><strong>左侧导航栏</strong>按功能分类排列所有设置选项卡，点击即可切换。<strong>右侧内容面板</strong>显示当前选项卡的具体配置项。</p><p>设置页面共包含 <strong>13 个功能模块</strong>，分布在以下几个大类中：</p><hr><h2 id="选项卡一览" tabindex="-1">选项卡一览 <a class="header-anchor" href="#选项卡一览" aria-label="Permalink to &quot;选项卡一览&quot;">​</a></h2><h3 id="⚡-通用与启动项" tabindex="-1">⚡ 通用与启动项 <a class="header-anchor" href="#⚡-通用与启动项" aria-label="Permalink to &quot;⚡ 通用与启动项&quot;">​</a></h3><p>涵盖应用的<strong>核心运行时行为</strong>，包括：</p><ul><li><strong>配置管理</strong>：打开配置目录、导出/导入配置（ZIP 打包，支持合并/覆盖两种模式）</li><li><strong>窗口与托盘</strong>：显示托盘图标、关闭到托盘行为</li><li><strong>基础主题</strong>：跟随系统/浅色/深色模式切换</li><li><strong>侧边栏模式</strong>：默认/抽屉/下拉菜单三种布局</li><li><strong>网络代理</strong>：跟随系统/不使用/自定义代理（支持自定义代理 URL）</li><li><strong>时区设置</strong>：跟随系统或手动选择（支持全球时区列表）</li><li><strong>下载管理</strong>：默认下载路径、总是询问保存位置、下载完成通知等</li><li><strong>启动项管理</strong>：各工具的自动启动开关，内置熔断保护（连续失败自动禁用）</li><li><strong>主题色配置</strong>：五种颜色类型（主题/成功/警告/危险/信息）的预设与自定义</li><li><strong>CSS 样式覆盖</strong>：通过编写自定义 CSS 深度定制应用界面，支持预设管理和实时预览</li></ul><blockquote><p>详细说明见 <a href="./general-startup">通用与启动项</a> 和 <a href="./custom-css">CSS 样式覆盖</a>。</p></blockquote><h3 id="🎨-外观与壁纸" tabindex="-1">🎨 外观与壁纸 <a class="header-anchor" href="#🎨-外观与壁纸" aria-label="Permalink to &quot;🎨 外观与壁纸&quot;">​</a></h3><p>应用的<strong>视觉质感控制中心</strong>，分为壁纸管理和界面特效两大部分：</p><p><strong>壁纸管理</strong>：</p><ul><li>静态壁纸 / 轮播模式（支持间隔、随机/顺序播放）</li><li>内置壁纸（预设网格选择）/ 自定义（文件选择、目录选择）</li><li>四种填充模式（覆盖/包含/拉伸/平铺），拼贴模式附带缩放、旋转、翻转</li></ul><p><strong>界面质感</strong>：</p><ul><li>UI 特效全局开关（透明度与模糊）</li><li>基础不透明度 / 分离窗口独立不透明度</li><li>背景色叠加（支持 16 种 CSS 混合模式、屏幕吸色、壁纸自动取色）</li><li>主题色自动提取（柔和/鲜艳/亮部/暗部四种策略）</li><li>UI 模糊（毛玻璃）开关 + 强度控制</li><li>边线不透明度与宽度、代码块背景不透明度</li></ul><p><strong>窗口特效（实验性）</strong>：</p><ul><li>模糊 (Blur) / 亚克力 (Acrylic) / 云母 (Mica) 原生窗口效果</li><li>窗口背景独立不透明度、窗口阴影开关</li></ul><blockquote><p>详细说明见 <a href="./appearance">外观与壁纸</a>。</p></blockquote><h3 id="🧩-工具模块" tabindex="-1">🧩 工具模块 <a class="header-anchor" href="#🧩-工具模块" aria-label="Permalink to &quot;🧩 工具模块&quot;">​</a></h3><p><strong>工具显示与排列管理面板</strong>：</p><ul><li><strong>可见性控制</strong>：工具卡片显示/隐藏开关，支持全选/全不选批量操作</li><li><strong>排序管理</strong>：拖拽 ↕ 排序手柄调整主页显示顺序，同步更新侧边栏</li><li><strong>重置顺序</strong>：一键恢复默认工具排列</li></ul><blockquote><p>详细说明见 <a href="./tool-management">工具管理</a>。</p></blockquote><h3 id="🔑-ai-服务配置" tabindex="-1">🔑 AI 服务配置 <a class="header-anchor" href="#🔑-ai-服务配置" aria-label="Permalink to &quot;🔑 AI 服务配置&quot;">​</a></h3><p><strong>LLM 服务渠道管理器</strong>，涵盖以下独立配置模块：</p><ul><li><strong><a href="./llm-service">LLM AI 服务配置</a></strong>：管理 API 提供商的渠道信息，支持多渠道 CRUD、拖拽排序、多 API Key 负载均衡、模型管理、连接测试。</li><li><strong><a href="./model-metadata">AI 模型元数据配置</a></strong>：通过规则匹配为模型分配图标和分组，支持四种匹配类型（Provider/Model/Prefix/Group）和正则表达式。</li><li><strong><a href="./ocr-service">云端 OCR 服务</a></strong>：管理 OCR 服务渠道，支持标准 API 和自定义 API 请求配置。</li><li><strong><a href="./user-profiles">用户档案管理</a></strong>：管理 LLM 聊天的用户档案，包含头像上传、富文本样式行为配置。</li></ul><h3 id="📋-日志与资产管理" tabindex="-1">📋 日志与资产管理 <a class="header-anchor" href="#📋-日志与资产管理" aria-label="Permalink to &quot;📋 日志与资产管理&quot;">​</a></h3><p><strong>日志系统</strong>和<strong>资产存储配置</strong>的管理面板：</p><p><strong>日志设置</strong>：</p><ul><li>日志级别（DEBUG/INFO/WARN/ERROR，实时生效）</li><li>文件日志与控制台日志独立开关</li><li>缓冲区大小配置（500-50000 条）、文件分割阈值（1MB-20MB）</li><li>实时日志统计面板（各类别日志条数）</li><li>操作入口：打开日志目录、导出日志、清空缓冲区、生成测试日志</li></ul><p><strong>资产管理</strong>：</p><ul><li>资产存储路径配置（显示默认路径 + 自定义路径选择）</li><li>路径缓存自动刷新，重置一键恢复</li></ul><blockquote><p>详细说明见 <a href="./logs-assets">日志与资产管理</a>。</p></blockquote><h3 id="i️-关于与许可" tabindex="-1">ℹ️ 关于与许可 <a class="header-anchor" href="#i️-关于与许可" aria-label="Permalink to &quot;ℹ️ 关于与许可&quot;">​</a></h3><p><strong>应用信息与支持页面</strong>：</p><ul><li>名称与版本信息（来自 Tauri API）</li><li>检查更新（从 GitHub Releases API 获取，支持 Semantic Version 对比）</li><li>项目链接（开发者、仓库地址、许可证）</li><li>支持项目（GitHub Star、爱发电赞助）</li><li>版权信息</li></ul><blockquote><p>详细说明见 <a href="./about">关于与许可</a>。</p></blockquote><hr><h2 id="配置持久化说明" tabindex="-1">配置持久化说明 <a class="header-anchor" href="#配置持久化说明" aria-label="Permalink to &quot;配置持久化说明&quot;">​</a></h2><p>AIO Hub 的所有设置都存储在本地文件系统中，<strong>不会上传到任何远程服务器</strong>。</p><h3 id="存储位置" tabindex="-1">存储位置 <a class="header-anchor" href="#存储位置" aria-label="Permalink to &quot;存储位置&quot;">​</a></h3><p>配置文件位于应用的<strong>数据目录</strong>下，你可以通过设置中的「打开配置目录」按钮快速访问。</p><h3 id="备份与迁移" tabindex="-1">备份与迁移 <a class="header-anchor" href="#备份与迁移" aria-label="Permalink to &quot;备份与迁移&quot;">​</a></h3><p>通过通用设置中的<strong>配置导出/导入</strong>功能，你可以：</p><ol><li><strong>导出配置</strong>：将所有模块的配置打包为 ZIP 压缩包</li><li><strong>导入配置</strong>：支持两种模式—— <ul><li><strong>合并导入</strong>：保留现有配置，仅更新导入文件中存在的项</li><li><strong>覆盖导入</strong>：完全替换为导入文件中的配置</li></ul></li></ol><blockquote><p>建议在重大版本更新前备份配置，以便随时恢复。</p></blockquote><h3 id="实时生效" tabindex="-1">实时生效 <a class="header-anchor" href="#实时生效" aria-label="Permalink to &quot;实时生效&quot;">​</a></h3><p>大多数设置项（如主题切换、日志级别、代理模式等）修改后<strong>即时生效</strong>，无需重启应用。部分设置（如资产存储路径）仅影响后续操作，已有数据不会自动迁移。</p><hr><blockquote><p><strong>下一步</strong>：从 <a href="./appearance">外观与壁纸</a> 开始，打造你专属的视觉风格。</p></blockquote>`,55)])])}const d=s(o,[["render",r]]);export{c as __pageData,d as default};
